import * as React from 'react';
import type { Meta } from '@storybook/react';
import { Text, ExpandableText, Dialog, Popover, ConfigProvider, FloatingUIPopperSidecar } from '../..';

export default {
  title: 'Components/ExpandableText/临时示例',
} satisfies Meta;

const content =
  // eslint-disable-next-line max-len
  '字节跳动于2012年3月创立。目前，字节跳动拥有“今日头条”、“抖音”、“火山小视频”等多款客户端产品及对应的网站。作为一家移动互联网公司，我们怀揣“全球创作与交流平台”的企业愿景，秉承“和优秀的人做有挑战的事，保持简单灵活的机制；提高透明度和信息分享效率，基于愿景目标自我驱动”的管理理念，坚持追求极致、务实敢为、开放谦逊、坦诚清晰、始终创业、多元兼容的字节范，我们推行扁平化的人性化的管理方式，以期激发每位同学在工作中的活力。此外，公司也在力所能及的范围内，最大限度地为员工营造一个良好、舒适的工作环境。';

const node = (
  <Text as="div">
    <ExpandableText>{content}</ExpandableText>
  </Text>
);

export const IssueScale = () => <div style={{ border: '1px solid red', transform: 'scale(0.7)' }}>{node}</div>;

export const IssueDialog = () => {
  const [visible, setVisible] = React.useState(false);
  return (
    <>
      <button
        type="button"
        onClick={() => {
          setVisible(true);
        }}
      >
        toggle dialog
      </button>
      <Dialog
        visible={visible}
        onCancel={() => {
          setVisible(false);
        }}
      >
        <div style={{ border: '1px solid red' }}>{node}</div>
      </Dialog>
    </>
  );
};

export const IssueRcTrigger = () => (
  <>
    <Popover visible content={<div style={{ border: '1px solid red' }}>{node}</div>}>
      <div>
        <button type="button">button</button>
      </div>
    </Popover>
    <ConfigProvider PopperSidecar={FloatingUIPopperSidecar}>
      <Popover visible content={<div style={{ border: '1px solid red' }}>{node}</div>}>
        <div>
          <button type="button">button</button>
        </div>
      </Popover>
    </ConfigProvider>
  </>
);
